const portfolio = $input.all().map((item, index) => {
  const quantity = parseFloat($('Google Sheet New Row Add Trigger').all()[index].json.Quantity);
  const purchasePrice = parseFloat($('Google Sheet New Row Add Trigger').all()[index].json['Purchase Price']);
  const currentPrice = Object.values(item.json.prices)[0].last_price;

  const currentValue = quantity * currentPrice;
  const gainLoss = currentValue - (quantity * purchasePrice);

  return {
    name: Object.values(item.json.prices)[0].symbol,
    PurchasePrice: purchasePrice,
    Quantity: quantity,
    CurrentValue: currentValue,
    GainLoss: gainLoss,
  };
});

return { 
    json: {
      portfolio: portfolio
    }
};

